"""
MKT Original Commentary — Mark chapters 3–4
Run: python3 scripts/zc-original-mark-3-4.py

Source data used:
- data/interlinear/mark.json
- data/translation/draft/mediating/mark.json
- data/commentary/mkt-original/mark.json (existing entries skipped by merge_comm)

Key decisions in this range:
- v3:5 orge + syllypoumenos: only place in Mark where Jesus is explicitly said to be angry
  AND grieved simultaneously — genuine dual emotional state, not softened
- v3:21 hoi par\' autou: "those beside him" = family; kratEsai = seize, not merely "take care of"
- v3:29 aiOniou hamartias: "eternal sin" — unique NT expression, not "unforgivable sin" per se
- v4:12 hina formula: "in order that" — hardening purpose of parables (Isa 6:9-10), not "so that"
- v4:27 automatE: NT hapax, "by itself/automatically" — the key word of the seed-growth parable
- v4:39 sitOpa, pephimOso: same muzzle-verb (phimoO) used on the demon in 1:25
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK = {
  "3": {
    "1": '<p><strong>Eiselthen eis ten synagOgen, kai En ekei anthrOpos exErammenen echOn ten cheira</strong> — he entered again into the synagogue, and there was a man who had a withered hand — <em>exErammenE</em> (withered, dried up — from <em>xerainO</em>, to dry out) is the Greek medical term for a limb that has lost function through atrophy or nerve damage. The synagogue setting repeats the pattern of 1:21-28: the place of Torah instruction becomes the arena of messianic authority. The unnamed man\'s condition is publicly visible, making the Sabbath dilemma equally public.</p>',
    "2": '<p><strong>Kai paretEroun auton ei tois sabbasin therapeusei auton, hina katEgorEsOsin autou</strong> — and they were watching him closely to see if he would heal him on the Sabbath, in order that they might accuse him — <em>paretEroun</em> (imperfect of <em>paratEreO</em>, to watch beside, observe closely, lie in wait) is legal surveillance: they are gathering evidence for a formal accusation (<em>katEgorEsOsin</em>, legal charge). The purpose clause (<em>hina</em> + subjunctive) makes the intent explicit: the healing they are about to witness is pre-interpreted as potential grounds for prosecution. The Sabbath healing is being set up as a legal trap.</p>',
    "3": '<p><strong>Kai legei tO anthrOpO tO exErammenen ten cheira</strong> — and he said to the man who had the withered hand — Jesus addresses the man directly before resolving the legal question, staging the healing as a public event (<em>egeire eis to meson</em> = rise into the middle). The command to stand in the center (<em>meson</em>) removes the man from obscurity and makes the healing fully visible to everyone in the synagogue. There will be no ambiguity about what happens or who does it.</p>',
    "4": '<p><strong>Exestin tois sabbasin agathon poiesai E kakOpoiesai, psychen sOsai E apokteinai?</strong> — is it lawful on the Sabbath to do good or to do evil, to save life or to kill? — the antithesis is sharp: doing good vs. doing evil, saving life vs. killing. Jesus frames the question so that refusing to heal is itself a moral act — inaction on behalf of suffering is not a neutral Sabbath posture but a form of evil. <strong>Hoi de esiOpOn</strong> — but they remained silent — the silence is not reverence but legal strategy: answering either way is a trap. Their silence confirms that they have no principled answer; they are not engaged in genuine halakhic debate but in evidence-gathering.</p>',
    "5": '<p><strong>Kai periblepsamenos autous met\' orgEs, syllypUmenos epi te pOrOsei tes kardias autOn</strong> — and looking around at them with anger, grieved at the hardness of their hearts — the dual emotional state is unique in the Gospels: <em>orge</em> (anger, righteous fury — same word as Isa 66:15; Rom 1:18 for divine wrath) and <em>syllypoumenos</em> (co-grieved, deeply distressed — the <em>syn</em> prefix adds the communal dimension: he shares in their suffering). Jesus is angry at the hardness and simultaneously grieved by it. The heart-hardness (<em>pOrOsis tes kardias</em> — <em>pOrOsis</em> = petrification, callusing) is the same condition described in Mark 6:52 (disciples after the feeding) and 8:17 — a recurring Markan diagnosis.</p>',
    "6": '<p><strong>Kai exelthontes hoi PharisaiOi euthys meta tOn HErOdianOn symBoulion edidoun kat\' autou hopOs auton apolEsOsin</strong> — and the Pharisees immediately went out and took counsel with the Herodians against him, how they might destroy him — <em>euthys</em>; the immediate consultation with the Herodians is surprising: the Pharisees (a purity-observance movement) and the Herodians (a political party supporting the Herodian dynasty) had conflicting agendas and mutual suspicion. Their alliance against Jesus is the political equivalent of the Sadducee-Pharisee alliance in 12:13-17: opposition to Jesus unites otherwise incompatible groups. <em>ApolEsOsin</em> (destroy) — this is the earliest death-plot in Mark, provoked by a healing.</p>',
    "7": '<p><strong>Kai ho IEsous meta tOn mathEtOn autou anechOrEsen pros ten thalassan</strong> — and Jesus with his disciples withdrew toward the sea — <em>anechOrEsen</em> (withdrew, retreated) is the response to the death-plot of v.6: strategic withdrawal rather than direct confrontation. The movement toward the lake creates the outdoor teaching space of 4:1-2. <strong>Kai poly plEthos apo tes Galilaias EkolouthEsen</strong> — and a great multitude from Galilee followed — the following crowd is pan-regional: Galilee (v.7), Judea, Jerusalem, Idumea, Transjordan, Tyre and Sidon (v.8). The geographic spread is Markan staging for the universal scope of the mission.</p>',
    "8": '<p><strong>Kai apo Ierosolymön kai apo tes Idoumaias kai peran tou Iordanou kai peri Tyron kai Sidona</strong> — and from Jerusalem and from Idumea and beyond the Jordan and around Tyre and Sidon — the geographic list deliberately spans Jewish and Gentile territory: Idumea (south of Judea, the homeland of the Herodians), Transjordan (east), and Tyre/Sidon (Phoenician cities of the northwest coast, Gentile territory). The anticipation of the Gentile mission is embedded in the crowd geography. <strong>AkOontes hosa poiei Elthan pros auton</strong> — hearing all he was doing, they came to him — fame (<em>akouO</em> = hearing) as the medium of approach, consistent with the <em>akoe</em> pattern of 1:28.</p>',
    "9": '<p><strong>Kai eipen tois mathEtais autou hina ploiarion proskarte autO dia ton ochlon</strong> — and he told his disciples that a small boat should be ready for him because of the crowd — <em>ploiarion</em> (small boat, diminutive of <em>ploion</em>) is prepared as an escape valve: the crowd pressure was becoming physical (v.10). The boat enables Jesus to continue teaching at the lake without being overwhelmed (cf. 4:1 where the boat becomes the teaching platform). <em>Hina mE thlibOsin auton</em> — in order that they would not press him — <em>thlibO</em> (to press, crush, afflict) describes the physical crush of the crowd. Mark\'s vivid realism: the healer was in danger of being physically overwhelmed by those seeking healing.</p>',
    "10": '<p><strong>Pollous gar etherapeuse, hOste epipiptein autO hina autou hapsOntai hosoi eichon mastigas</strong> — for he healed many, so that those who had diseases were pressing upon him in order to touch him — <em>epipiptO</em> (to fall upon, press heavily upon) describes the crowd\'s physical aggression: those with <em>mastigas</em> (scourges, plagues, afflictions — literally "whips," the word for the physical blows of a whipping; used metaphorically for illness) were pressing themselves against him. The connection between healing and touch is distinctive to Mark\'s physicality: the healings in ch.5 (woman with hemorrhage, 5:28-30; Jairus\'s daughter, 5:41) both involve touch. The crowd\'s instinct to touch him is not wrong.</p>',
    "11": '<p><strong>Kai ta pneumata ta akatharta, hotan auton etheOroun, prosEpipton autO kai ekrazon legontes hoti Sy ei ho hyios tou theou</strong> — and the unclean spirits, whenever they saw him, fell before him and cried out saying "you are the Son of God" — the <em>hotan</em> + imperfect construction indicates recurring behavior: every encounter with unclean spirits produced the same response. <em>ProsEpipton</em> (fell before, prostrated themselves — the posture of submission before a superior power) + <em>ekrazon</em> (they cried out). The demonic recognition and involuntary submission is the third instance of the Messianic Secret pattern. The title <em>ho hyios tou theou</em> (the Son of God) is identical to the baptismal declaration of 1:11; demons know what disciples do not yet understand.</p>',
    "12": '<p><strong>Kai polla epetima autois hina mE auton phaneron poiEsOsin</strong> — and he gave them many strict orders not to make him known/manifest — <em>epitimaO</em> (to charge/rebuke strictly, command with authority) + <em>phaneron poiEsOsin</em> (to make manifest, make publicly known). The Messianic Secret command here is the most explicit: the demons are ordered not to reveal him. The word <em>phaneros</em> (manifest, visible, publicly disclosed) is the disclosure term Mark uses at 4:22 for what will ultimately be revealed; the secret suppression is not permanent but a matter of timing and proper channel.</p>',
    "13": '<p><strong>Kai anabainei eis to oros kai proskAleitai hous Ethelen autos</strong> — and he went up onto the mountain and summoned those whom he himself wanted — the ascent of the mountain is a Sinai-echo: the law-giver ascended the mountain; now the one with greater authority constitutes a new community. <em>Hous Ethelen autos</em> (those whom he himself wanted) — the sovereign, personal choice (<em>autos</em> emphatic) is the basis of the calling: they are chosen, not volunteers. <em>Kai apElthon pros auton</em> — and they came to him — the response matches the sovereign call: no resistance, no deliberation mentioned.</p>',
    "14": '<p><strong>Kai epoiEsen dOdeka hina Osin met\' autou</strong> — and he appointed/made twelve so that they might be with him — the founding purpose of the Twelve is stated first: <em>hina Osin met\' autou</em> (in order that they might be with him) — the primary calling is not to do but to be with. The second and third purposes follow: <em>kai hina apostellE autous kEryssein</em> (to send them out to preach) and <em>kai echein exousian ekballein ta daimonia</em> (to have authority to cast out demons). The ordering matters: being with Jesus precedes and grounds the sending; presence is the source of the commission\'s authority.</p>',
    "15": '<p><strong>Kai echein exousian ekballein ta daimonia</strong> — and to have authority to cast out demons — the three purposes of the Twelve appointment (v.14-15) match the three activities of Jesus\'s own ministry pattern: presence/relationship (v.14a), preaching (v.14b), exorcism (v.15). The Twelve are constituted as extensions of Jesus\'s own mission, carrying the same authority (<em>exousia</em>) that distinguished his teaching (1:22) and his commands to unclean spirits (1:27). The commissioning is a delegation of the Christological authority, not a separate source of power.</p>',
    "16": '<p><strong>Kai epoiEsen tous dOdeka, kai epethEken onoma tO SimOni Petron</strong> — and he appointed the twelve, and he gave Simon the name Peter — <em>epethEken onoma</em> (placed/bestowed a name upon) — the act of naming carries authority: in the OT, God renames Abram/Abraham, Jacob/Israel; the one who names exercises sovereignty over the named. <em>Petros</em> (Peter) is the Greek transliteration of the Aramaic <em>Kēphā</em> (Cephas, rock/stone, 1 Cor 1:12; Gal 1:18). The renaming precedes the full commissioning of Peter\'s apostolic role; it is a prophetic act whose full significance becomes clear only in retrospect.</p>',
    "17": '<p><strong>Kai Iakōbon ton tou Zebedaiou kai IOannEn ton adelphon tou Iakōbou, kai epethEken autois onomata BoanErges, ho estin huioi brontEs</strong> — and James the son of Zebedee and John the brother of James, and he gave them the name Boanerges, which is "sons of thunder" — <em>BoanErges</em> is a Greek transliteration of an Aramaic expression (possibly <em>bney ragsha</em> or <em>bney re\'em</em>); Mark provides the Greek translation (<em>huioi brontEs</em> = sons of thunder). The name is preserved only in Mark and is not used elsewhere in the NT. The reason for the nickname is never explained; retrospectively, it may reflect the temperament displayed in Luke 9:54 (calling down fire) or the ambition of Mark 10:37 (requesting seats of honor). Mark uniquely preserves the Aramaic nickname alongside its translation.</p>',
    "18": '<p><strong>Kai Andrean kai Philippon kai BartholomaIon kai Matthaion kai ThOman kai Iakōbon ton tou Alphaiou kai Thaddalon kai SimOna ton KananaIon</strong> — and Andrew and Philip and Bartholomew and Matthew and Thomas and James the son of Alphaeus and Thaddaeus and Simon the Cananaean — the list of apostles (cf. Matt 10:2-4; Luke 6:14-16; Acts 1:13) varies in ordering but shares the core Twelve. <em>KananaIos</em> (the Cananaean) is not "from Cana" but the Aramaic equivalent of the Greek <em>ZElOtEs</em> (Zealot, Luke 6:15; Acts 1:13), likely indicating association with or origin in a zealot movement. The list includes a tax collector (Levi/Matthew, v.14 of ch.2) and a zealot — political opposites in one apostolic community.</p>',
    "19": '<p><strong>Kai Ioudan Iskariōth, hos kai paredōken auton</strong> — and Judas Iscariot, who also betrayed him — the final name on the list is the only one with an appended identification, and that identification is <em>hos kai paredōken auton</em> (who also betrayed him). The <em>kai</em> (also) is pointed: Judas was appointed to be with Jesus and to preach and to cast out demons — and he also betrayed him. The betrayal is noted at the moment of the appointment, not as an afterthought. <em>Iskariōth</em> may derive from <em>ish-Keriyot</em> (man of Kerioth, a Judean town), identifying Judas as the only non-Galilean among the Twelve.</p>',
    "20": '<p><strong>Kai erchontai eis oikon, kai synerchetai palin ochlos, hOste mE dynasthai autous mEde arton phagein</strong> — and they entered a house, and the crowd came together again, so that they could not even eat bread — the domestic retreat is immediately overwhelmed. <em>Mēde arton phagein</em> (not even to eat bread) is a vivid detail of the extreme demand on Jesus: even the minimum physical sustenance is impossible. This detail recurs at 6:31 (<em>oudE phagein eukairoun</em>). The crowds\' need is so constant that the normal rhythms of eating are disrupted. Mark\'s realism here — the press of the crowds does not allow even meals — gives the ministry a physical exhaustion dimension.</p>',
    "21": '<p><strong>Kai akousantes hoi par\' autou exElthon kratEsai auton, elegon gar hoti exestE</strong> — and those beside him, having heard, went out to seize him; for they said, "he is beside himself" — <em>hoi par\' autou</em> (those beside him, those of his household) almost certainly refers to Jesus\'s family, confirmed by v.31\'s reference to his mother and brothers. <em>KratEsai</em> (to seize, take hold of by force — the same verb used for arresting Jesus in 14:1,44,46,49) is forceful: they intended to physically remove him. <em>ExestE</em> (he has gone out of himself, he is beside himself, out of his mind) — the family\'s diagnosis is that Jesus has lost his sanity; the religious authorities\' diagnosis (v.22) is that he is demonized. Both interpretations of Jesus\'s behavior are rejected by the narrative.</p>',
    "22": '<p><strong>Kai hoi grammateis hoi apo Ierosolymōn katabanteEs elegon hoti BeelZeboul echei kai hoti en tO archonti tOn daimonion ekballei ta daimonia</strong> — and the scribes who came down from Jerusalem were saying "he has Beelzebul" and "by the ruler of demons he casts out demons" — the Jerusalem delegation arriving in Galilee is significant: this is not a local Pharisaic grumbling but a formal evaluation sent from the religious capital. <em>BeelZeboul</em> (various spellings; possibly <em>ba\'al-zebul</em> = lord of the high dwelling or lord of flies/filth, cf. 2 Kgs 1:2-3) is identified as the prince/ruler of demons (<em>archonti tOn daimonion</em>). The charge is the mirror-inverse of the truth: Jesus casts out demons by the Spirit of God (Matt 12:28); they attribute the same act to the demonic ruler.</p>',
    "23": '<p><strong>Kai proskalesamenos autous en parabolais elegen autois, POs dynatai Satanas Satanan ekballein?</strong> — and having called them to him, he began to speak to them in parables: "how can Satan cast out Satan?" — <em>proskalesamenos autous</em> (having called them to him) — Jesus initiates the debate by drawing his accusers into proximity; he does not avoid the charge but responds directly. The parabolic counter-argument begins with an internal-coherence question: an exorcist who serves Satan would be self-defeating. <em>Satanas Satanan ekballein</em> — Satan casting out Satan — the logical contradiction of the accusation is stated in the most compressed form: the premise makes the action structurally impossible.</p>',
    "24": '<p><strong>Kai ean basileia eph\' heautEn meristhE, ou dynatai stathEnai hE basileia ekeinE</strong> — and if a kingdom is divided against itself, that kingdom cannot stand — the argument from analogy: a divided kingdom is structurally self-defeating. <em>Meristhē</em> (divided, distributed, parceled out — from <em>merizO</em>) applied to a kingdom: a realm at war with itself cannot sustain its own coherence. The application to the exorcism charge: if Jesus\'s exorcisms are Satanic acts, Satan is destroying his own domain. The internal coherence of the demonic realm (however disordered) would be undermined by casting out its own members.</p>',
    "25": '<p><strong>Kai ean oikia eph\' heautEn meristhE, ou dynEsetai hE oikia ekeinE stathEnai</strong> — and if a house is divided against itself, that house cannot stand — the household (smaller than a kingdom) provides the second analogical level: domestic division produces structural collapse. The household image is immediate and observable; every hearer knows that a family that fights against itself destroys itself. The double analogy (kingdom, v.24; household, v.25) establishes the principle at both scales before the application to the demonic realm in v.26.</p>',
    "26": '<p><strong>Kai ei ho Satanas anestE eph\' heauton kai emeristhE, ou dynatai stathEnai alla telos echei</strong> — and if Satan has risen against himself and is divided, he cannot stand but has come to an end — the application of the analogy to Satan directly: if the exorcisms represent Satan acting against himself, it means his end (<em>telos echei</em> = has an end, is finished). The Christological implication: that Satan\'s kingdom is in fact falling is correct, but the reason is not internal division but the arrival of the stronger one (cf. 1:7: <em>ho ischyroteros mou</em>) who binds him from outside.</p>',
    "27": '<p><strong>All\' ou dynatai oudeis eis ten oikian tou ischyrou eiselthOn ta skeue autou diarpasai, ean mE prOton ton ischyron dEsE kai tote ten oikian autou diarpasei</strong> — but no one can enter the house of the strong man and plunder his goods unless first he binds the strong man; and then he will plunder his house — the strong-man parable is the Christological key to the entire Beelzebul controversy. <em>HO ischyros</em> (the strong man) = Satan; Jesus is the one who has <em>first bound him</em> (<em>prOton ton ischyron dEsE</em>), making the exorcisms possible. The exorcisms are not signs of demonic alliance but signs of demonic defeat: Jesus plunders the strong man\'s house because he has already bound the strong man. The binding may refer to the wilderness temptation (1:13) or to the eschatological power of the kingdom.</p>',
    "29": '<p><strong>Hos d\' an blasphEmEsE eis to pneuma to hagion, ouk echei aphesin eis ton aiOna, alla enochos estin aiOniou hamartEmatos</strong> — but whoever blasphemes against the Holy Spirit does not have forgiveness unto the age, but is guilty of an eternal sin — <em>aiOniou hamartEmatos</em> (eternal sin/offense — <em>aiOnios</em> = of the age, pertaining to the coming age, age-long) is unique in the NT. The standard translation "unforgivable sin" accurately captures the practical meaning (<em>ouk echei aphesin eis ton aiOna</em> = does not have forgiveness for the age) but the term itself is <em>eternal sin</em>, emphasizing its age-to-come consequences. The sin is the attribution of the Holy Spirit\'s works (exorcism) to the demonic — a permanent inversion that places oneself outside the Spirit\'s reach who would grant repentance.</p>',
    "30": '<p><strong>Hoti elegon, Pneuma akatharton echei</strong> — because they were saying "he has an unclean spirit" — v.30 is Mark\'s editorial explanation of why Jesus spoke the unforgivable-sin saying: it was a direct response to the specific charge that he was possessed by an unclean spirit. The explanation clarifies the referent of "blasphemy against the Holy Spirit": it is specifically the inversion of Spirit-empowerment and demonic possession — claiming that the Holy Spirit\'s exorcistic work is instead the work of an unclean spirit. This is not a general category of sin but a very specific theological inversion.</p>',
    "31": '<p><strong>Kai erchontai hE mEtEr autou kai hoi adelphoi autou kai exO stEkontes apesteilan pros auton kalountes auton</strong> — and his mother and his brothers came and standing outside they sent word to him, calling him — the family arrives (cf. v.21 where they went out to seize him). <em>HExO stEkontes</em> (standing outside) is spatially significant: Jesus\'s physical family is outside the house; the crowd is inside. The narrative has already set up the redefinition of family in vv.33-35. <em>Hoi adelphoi autou</em> (his brothers) — the natural reading is biological siblings; the alternative (cousins, or children of Joseph from a previous marriage) is theologically motivated but grammatically strained.</p>',
    "32": '<p><strong>Kai ekatheto peri auton ochlos, kai legousin autO, Idou hE mEtEr sou kai hoi adelphoi sou exO zEtousin se</strong> — and a crowd was sitting around him, and they said to him: "look, your mother and your brothers are outside seeking you" — <em>ekatheto peri auton</em> (was sitting in a circle around him) — the crowd physically surrounds Jesus in the posture of disciples receiving teaching. This spatial arrangement will become the answer to the question in v.33: the circle around him is the definition of his family. <em>ZEtousin se</em> (seeking you) — the same verb used in 1:37 (everyone seeks you!) and in 3:32 and will be used of those who seek Jesus\'s death. The usage here is neutral but carries the ambiguous charge of the word.</p>',
    "33": '<p><strong>Kai apokritheis autois legei, Tis estin hE mEtEr mou E hoi adelphoi mou?</strong> — and answering them he said: "who is my mother and who are my brothers?" — the rhetorical question (<em>tis estin</em> = who is?) sets up the redefinition. The question is not a denial of biological relationship but a relativization of it: the biological bond, however real, is not the primary or ultimate category of kinship. Jesus will answer with a gesture (v.34) and a declarative statement (v.35) that redefines family on the basis of shared orientation toward the Father\'s will rather than biological descent.</p>',
    "34": '<p><strong>Kai periblepsamenos tous peri auton kuklO kathEmenous legei, Ide hE mEtEr mou kai hoi adelphoi mou</strong> — and looking around at those sitting in a circle around him he said: "here are my mother and my brothers" — <em>periblepsamenos</em> (having looked around — the Markan characteristic scanning gaze, also at 3:5; 5:32; 9:8; 10:23) with <em>kuklO</em> (in a circle) — the same word as the crowd\'s seating arrangement in v.32. The gestural answer: <em>Ide</em> (Look! Behold!) pointing to the seated disciples. The ones gathered around him in the posture of receiving teaching are identified as his mother and brothers — a community of belonging constituted by presence with Jesus and attentiveness to his word.</p>',
    "35": '<p><strong>Hos an poiEsE to thelEma tou theou, houtos adelphos mou kai adelphE kai mEtEr estin</strong> — whoever does the will of God, that one is my brother and sister and mother — the addition of <em>adelphE</em> (sister) to the male-focused terms brother and mother signals the inclusive scope of the new family. <em>Poieo to thelEma tou theou</em> (does the will of God) is the defining criterion: not biological descent, not ethnic identity, not religious observance as such, but active alignment with the Father\'s purpose. The same criterion appears in Matthew\'s Gospel in a different context (7:21; 12:50); here it defines not entry into the kingdom but membership in the family of Jesus.</p>'
  },
  "4": {
    "1": '<p><strong>Kai palin Erxato didaskein para ten thalassan</strong> — and again he began to teach beside the sea — <em>palin</em> (again) connects to the lakeshore teaching of 2:13; the outdoor setting by the lake is established as a regular venue. <strong>Kai synagetai pros auton ochlos pleistos, hOste auton eis ploion emBanta kathEsthai en te thalasse</strong> — and the largest crowd yet gathered to him, so that he got into a boat and sat in the sea — the superlative <em>pleistos</em> (very large, greatest crowd) signals escalation. The boat-as-podium removes Jesus from the pressing crowd (cf. 3:9) while allowing him to address everyone on the shore. The spatial arrangement — speaker in the boat, audience on the beach — creates an amphitheater effect, the water carrying his voice.</p>',
    "2": '<p><strong>Kai edidAsken autous en parabolais polla</strong> — and he was teaching them many things in parables — the imperfect <em>edidasken</em> (was teaching, ongoing) with <em>polla</em> (many things) establishes the parabolic teaching as a sustained mode, not a single occasion. <em>Parabolē</em> (parable — from <em>para</em> + <em>ballō</em>, to throw alongside) is the placing of two things side by side for comparison: the earthly scene (farming, fishing, domestic life) placed alongside the kingdom reality to illumine it. <strong>Kai elegen autois en te didachE autou</strong> — and he was saying to them in his teaching — the editorial transition signals that a representative parable follows.</p>',
    "3": '<p><strong>AkouEte</strong> — Listen! — the imperative opening is the parable\'s own call for the kind of attention that will yield understanding. The same verb <em>akouO</em> (to hear) appears at v.9 (<em>ho echōn Ōta akouein akouetō</em> = whoever has ears to hear let him hear) and v.12 (the Isaiah hearing-without-understanding quotation). The entire parable section is framed by the call to hear and the paradox of hearing without understanding. <strong>Idou exElthen ho speirOn speirai</strong> — behold a sower went out to sow — <em>idou</em> (behold) invites visual imagination. The historic present <em>exElthen</em> makes the scene immediate. The sower\'s identity is left entirely ambiguous until the interpretation in v.14 (the sower sows the word).</p>',
    "4": '<p><strong>Kai egeneto en tO speirein ho men epesen para ten hodon</strong> — and as he sowed, some fell beside the road — the fourfold soil sequence begins. <em>Para ten hodon</em> (beside/along the road) — the packed earth of a footpath through or beside the field: impenetrable to the seed, which lies on the surface. <strong>Kai Elthen ta peteina kai katephagen auto</strong> — and the birds came and ate it up — the immediate consumption leaves no trace of the seed\'s landing. The interpretation (v.15) identifies the birds with Satan who removes the word before it can take root.</p>',
    "5": '<p><strong>Kai allo epesen epi to petrOdes</strong> — and other seed fell on the rocky ground — <em>petrOdes</em> (rocky, full of rock — from <em>petra</em>, rock/bedrock) is soil with a thin layer over bedrock, not soil full of scattered stones. <strong>Hopou ouk eichen gen pollen, kai euthys exanEtEilen dia to mE echein bathos gEs</strong> — where it did not have much soil, and immediately it sprang up because it had no depth of soil — the speed of germination (<em>euthys</em>) is caused by the shallowness: without the need to penetrate deeply, the seed springs up quickly. The quick appearance is deceptive — the depth required for sustaining the plant is absent.</p>',
    "6": '<p><strong>Kai hote anEteilen ho Elios ekauma tIsthE kai dia to mE echein rizan exEranthE</strong> — and when the sun rose it was scorched, and because it had no root it dried up — <em>ekauma tIsthE</em> (was scorched — <em>kaumatizO</em> from <em>kauma</em>, burning heat) and <em>exEranthE</em> (was dried up — the same root <em>xErainO</em> as the withered hand of 3:1). The absence of root (<em>rizan</em>) is the lethal condition: the apparent vitality of v.5 (springing up quickly) masks the structural deficiency. The interpretation (v.17) identifies this with those who respond with joy but have no root and fall away under persecution.</p>',
    "7": '<p><strong>Kai allo epesen eis tas akanthas kai anebEsan hai akanthai kai synEpnixan auto kai karpon ouk edOken</strong> — and other seed fell into the thorns and the thorns came up and choked it and it did not give grain — <em>synEpnixan</em> (choked, strangled — from <em>sympnigO</em>, to choke together) describes the thorns growing up simultaneously with the grain and crowding it out. <em>Karpon ouk edOken</em> (gave no fruit/grain) is the diagnostic outcome: growth occurred but the productive end was prevented. The interpretation (v.19) identifies the thorns with the worries of the age, the deceitfulness of wealth, and desires for other things.</p>',
    "8": '<p><strong>Kai alla epesen eis ten gen ten kalEn kai ediDou karpon anabainonta kai auxanomena kai epheren en triakonta kai en hexEkonta kai en hekaton</strong> — and other seed fell into the good soil and was giving fruit, coming up and growing, and was bearing thirty and sixty and a hundredfold — the good soil produces triple gradations of yield: 30, 60, 100. The imperfect <em>ediDou</em> (was giving, kept giving) indicates sustained fruitfulness rather than a single harvest. The yields are remarkable by ancient agricultural standards (typical yields were 5-10 fold); the 30/60/100 is not uniformly extraordinary but varies — even the lowest good-soil yield is notable. The interpretation (v.20) simply names the outcome: they hear, accept, and produce a crop.</p>',
    "9": '<p><strong>Kai elegen, Ho echOn Ōta akouein akouetO</strong> — and he was saying: "whoever has ears to hear let him hear" — the hearing-call concludes the parable and picks up the opening imperative of v.3 (<em>akouete</em>). The idiom <em>ho echOn Ōta</em> (having ears) distinguishes the capacity for hearing from the mere anatomical possession of ears: the point is that spiritual perception is a gift or condition, not automatic. The reflexive structure (<em>akouein akouetO</em> — hearing/let-him-hear) intensifies: the one who can hear should really hear. The same formula appears in 4:23 and throughout the Gospels and Revelation (2:7,11,17,29 etc.).</p>',
    "10": '<p><strong>Kai hote egeneto kata monas, ErOtOn auton hoi peri auton syn tois dOdeka tas parabolas</strong> — and when he was alone, those around him along with the Twelve were asking him about the parables — <em>kata monas</em> (alone, apart — the idiom for private withdrawal from the public) creates the inner-circle setting for the explanation. The questioners are broader than just the Twelve: <em>hoi peri auton</em> (those around him) is the wider circle of committed followers, with the Twelve as the core. They ask about <em>tas parabolas</em> (the parables, plural) — not just the sower parable but the entire parabolic teaching mode. The question occasions the explanation of the parabolic method (vv.11-12) before the specific sower-interpretation (vv.13-20).</p>',
    "12": '<p><strong>Hina blepOntes blepOsin kai mE idOsin, kai akOuontes akOuOsin kai mE syniOsin, mEpote epistrepsOsin kai aphethe autois</strong> — in order that seeing they may see and not perceive, and hearing they may hear and not understand, lest they should turn and be forgiven — the <em>hina</em> (in order that) introduces a purpose clause citing Isa 6:9-10 — one of the most theologically difficult verses in the Gospels. The hardening purpose of parables: the parables are not merely pedagogy for the slow but vehicles of concealment for those who have placed themselves outside. Three proposed readings: (1) the <em>hina</em> is genuinely purposive (God\'s sovereign hardening, cf. Rom 9-11); (2) the <em>hina</em> translates an Aramaic <em>de-</em> that can be either purpose or result; (3) the context qualifies the hardening as God\'s response to existing rejection. The Isaianic echo is intentional: Mark\'s Jesus stands in the line of Isaiah, whose proclamation both revealed and concealed.</p>',
    "13": '<p><strong>Kai legei autois, Ouk oidate tEn parabolEn tautEn, kai pOs pasas tas parabolas gnOsesthe?</strong> — and he said to them: "do you not know this parable? then how will you know all the parables?" — <em>OuK oidate</em> (do you not know/understand) implies the disciples\' failure to grasp the parable is a failure that calls for explanation. The meta-question — "if you don\'t get this parable, how will you understand any parable?" — establishes the sower parable as foundational: it is the <em>key</em> parable, the one whose interpretive logic (hearing the word, response types, fruit or no fruit) governs all the others. Understanding this parable is prerequisite to understanding the parabolic method as a whole.</p>',
    "14": '<p><strong>Ho speirOn ton logon speirei</strong> — the sower sows the word — the interpretation\'s first move is the identification of the seed: <em>ton logon</em> (the word, the gospel message). The sower\'s identity remains ambiguous — Jesus, the disciples, any preacher. The interpretive focus falls entirely on the soil (the receiver-types), not on the sower. <em>Ton logon</em> is the technical term for the early Christian message (Acts 4:4; 6:2,4; 8:4; 1 Thess 1:6), indicating that the parable was read in the early church as a map of mission-experience: why does the same proclamation produce such different results?</p>',
    "15": '<p><strong>Houtoi de eisin hoi para ten hodon hopou speiretai ho logos, kai hotan akOusOsin, euthys erchetai ho Satanas kai airei ton logon ton esparmenon eis autous</strong> — these are the ones along the road where the word is sown; and when they hear, immediately Satan comes and takes away the word that was sown in them — <em>euthys erchetai ho Satanas</em> (immediately Satan comes) — the <em>euthys</em> of demonic activity mirrors the <em>euthys</em> of Jesus\'s own activity. The immediacy of removal before the word can take root is the mechanism of the first soil\'s failure: the word never gets the chance to germinate. The Satanic taking-away is a forcible removal (<em>airei</em> = takes up, removes), not a gradual fading.</p>',
    "16": '<p><strong>Kai houtoi eisin homoiOs hoi epi ta petrOdE speiromenoi, hoi hotan akOusOsin ton logon euthys meta charas lambanousin auton</strong> — and these likewise are the ones sown on the rocky places, who when they hear the word immediately receive it with joy — the joy-reception (<em>meta charas lambanousin auton</em>) is the initial positive response that makes the rocky-ground hearer the most deceptive soil-type. The outward response is genuinely positive: immediate, joyful reception. <em>Euthys</em> again — the same immediacy that marks both Satanic removal (v.15) and the quick germination of shallow soil (v.5). Speed without depth is the danger.</p>',
    "17": '<p><strong>Kai ouk echousin rizan en heautois alla prosKairoi eisin, eita genomenes thlipseOs E diOgmou dia ton logon euthys skandalizontai</strong> — and they do not have root in themselves but are temporary; then when affliction or persecution comes because of the word, immediately they are caused to stumble — <em>prosKairoi</em> (temporary, time-limited — <em>pros</em> + <em>kairos</em>: for a season) contrasts with the <em>aiOnios</em> (eternal, age-long) character of what genuine discipleship produces. <em>SkandalizontaI</em> (are scandalized, caused to stumble — from <em>skandalon</em>, a trap-trigger or stumbling stone) is the technical term for apostasy in the face of pressure. The <em>dia ton logon</em> (because of the word) specifies that the persecution is a direct response to the gospel commitment.</p>',
    "18": '<p><strong>Kai alloi eisin hoi eis tas akanthas speiromenoi</strong> — and others are those sown among the thorns — the third soil-type receives its own interpretive verse (v.18) and an expanded list of the thorn-competitors in v.19. The naming of three specific "thorns" (worries, wealth-deceit, desires) is the most detailed interpretation among the four soils, suggesting that this type was particularly recognizable and dangerous in the early church context.</p>',
    "19": '<p><strong>Hai merimnaI tou aiOnos kai hE apatE tou ploutou kai hai peri ta loipa epithymiai eisporeuomenai sympnigousin ton logon kai akarpos ginetai</strong> — the worries of the age and the deceitfulness of wealth and the desires for other things, entering in, choke the word and it becomes unfruitful — three named thorns: <em>merimnaI tou aiOnos</em> (anxieties of the age), <em>apatE tou ploutou</em> (deceitfulness/seduction of wealth — <em>apatE</em> is active deception, not mere distraction), and <em>hai peri ta loipa epithymiai</em> (desires concerning other things). The common thread is displacement: the word is not opposed by these forces but crowded out. The final diagnosis (<em>akarpos ginetai</em> = becomes unfruitful) echoes the plant that gives no grain in v.7.</p>',
    "20": '<p><strong>Kai ekeinoi eisin hoi epi ten gen ten kalEn sparentes, hoi akOuousin ton logon kai paradechontai kai karpophorousin en triakonta kai en hexEkonta kai en hekaton</strong> — and those are the ones sown on the good soil, who hear the word and accept it and bear fruit, thirty and sixty and a hundredfold — the fourfold sequence climaxes in the good soil. <em>ParadechontaI</em> (accept, receive alongside — <em>para</em> + <em>dechomai</em>, to receive and hold onto) distinguishes genuine reception from the surface-acceptance of v.16 (<em>lambanousin</em>). The triple yield (30/60/100) mirrors v.8: genuine fruitfulness varies in degree but is genuinely fruitful at every level. The good-soil hearer is not an idealized perfect disciple but one who hears, receives, and actually produces.</p>',
    "21": '<p><strong>Kai elegen autois, MEti erchetai ho lychnos hina hypo ton modion tethE E hypo ten klinEn, ouch hina epi ten lychian tethE?</strong> — and he said to them: "the lamp is not brought in to be put under the bushel-basket or under the bed, is it? It is to be put on the lampstand, isn\'t it?" — <em>lychnos</em> (oil lamp) placed on the <em>lychnia</em> (lampstand, the raised holder for maximum illumination) — the household logic is self-evident. <em>Modion</em> (bushel, grain-measure container) and <em>klinE</em> (bed/couch) are the two unlikely lamp-hiding places: the lamp would be smothered under the basket and dangerously misused under the bed. The lamp has an inherent telos — to give light — and hiding it defeats its purpose.</p>',
    "22": '<p><strong>Ou gar estin ti krypton ean mE hina phanerOthE, oude egeneto apokryphon all\' hina elthE eis phaneron</strong> — for nothing is hidden except to be made manifest, and nothing has been concealed except to come into the open — the purpose clause (<em>hina phanerOthE ... hina elthE eis phaneron</em>) is key: hiddenness is not an end state but a temporary condition aimed at future disclosure. This reframes the parable-concealment of v.11-12: the mystery is hidden for a season (the pre-resurrection period), not permanently suppressed. The lamp saying and this disclosure saying together form a corrective to any misreading of Messianic-Secret concealment as permanent.</p>',
    "23": '<p><strong>Ei tis echei Ōta akouein, akouetO</strong> — if anyone has ears to hear, let him hear — the call to hearing appears for the second time in the chapter (cf. v.9), creating a bracket around the explanation of the parabolic method (vv.10-22). The repetition reinforces the central concern of the chapter: hearing is the critical faculty and the greatest variable in the reception of the word. The parable of the soils, the lamp, and the seed-growth are all variations on the theme of reception-and-response.</p>',
    "24": '<p><strong>Kai elegen autois, BlepEte ti akouEte. En O metrO metrEite metrEthEsetai hymin kai prostEthEsetai hymin</strong> — and he was saying to them: "pay attention to what you hear; with the measure you use it will be measured to you, and more will be added to you" — <em>blepEte ti akouEte</em> (pay attention to what you hear — <em>blepO</em> used for the quality of hearing, not merely its occurrence) combines the two primary senses for careful engagement. The measure-for-measure principle (<em>en O metrO metrEite metrEthEsetai hymin</em>) is a well-known Jewish proverbial saying (Mishnah Sotah 1:7; Matt 7:2 applies it to judgment); here it is applied to receptivity: the more attentive and active your hearing, the more you will receive.</p>',
    "25": '<p><strong>Hos gar echei, dothEsetai autO kai hos ouk echei, kai ho echei arthEsetai ap\' autou</strong> — for whoever has, it will be given to him; and whoever does not have, even what he has will be taken from him — the paradoxical give/take saying appears in three Synoptic contexts (Matt 13:12; 25:29; Luke 8:18; 19:26). In the context of hearing-receptivity: those who engage the word with active hearing receive more; those who receive it passively (or not at all) lose even the superficial reception they had. The saying applies the economic logic of interest-bearing investment: capital that is used grows; capital that is hoarded or unused is lost. Spiritual receptivity operates on the same principle.</p>',
    "27": '<p><strong>Kai katheude kai egeirEtai nykta kai hEmeraEn kai ho sporos blastA kai mEkynEtai hos ouk oiden autos</strong> — and he sleeps and rises night and day and the seed sprouts and grows, he himself does not know how — <em>hos ouk oiden autos</em> (he himself does not know how) — the farmer\'s ignorance of the growth mechanism is the central point. The growth is not his achievement or his understanding; it occurs independently of his knowledge. This is the parable\'s unique Markan contribution: not just the patience of waiting (Matt/Luke do not include this parable) but the specific emphasis on the farmer\'s non-comprehension. Kingdom growth operates beyond human understanding as well as human control.</p>',
    "28": '<p><strong>AutomatE hE gE karpophorei, prOton chorton, eita stachyn, eita plEre siton en tO stachyi</strong> — the earth produces fruit by itself: first the stalk, then the head, then the full grain in the head — <em>automatE</em> (by itself, automatically — from <em>autos</em> + <em>matos</em>/madness, hence "self-acting") is a NT hapax in this sense (2 Pet 2:14 and Acts 12:10 use it for automatic gates). The word emphasizes the intrinsic generative power of the earth-seed relationship that operates without human intervention. The three stages (<em>chortos</em> = grass/blade, <em>stachys</em> = head of grain, <em>plErEs sitos</em> = full mature grain) describe the organic sequence of grain development: the growth is orderly, progressive, and internally driven.</p>',
    "29": '<p><strong>Hotan de paradO ho karpos, euthys apostellei to drepanon, hoti parEstEken ho therismos</strong> — but when the fruit allows/permits, immediately he sends the sickle because the harvest has come — <em>paradO ho karpos</em> (when the fruit yields/delivers itself — <em>paradidOmi</em> used of the grain: it "gives itself over") is a vivid personification of the ripened grain\'s readiness. <em>ApostellEi to drepanon</em> (sends the sickle) echoes Joel 3:13 (<em>aposteilate drepana hoti parEstEken therismos</em> = send the sickle because the harvest has arrived), which is the eschatological harvest of judgment. The harvest-language frames the kingdom\'s growth as moving toward the final divine reckoning that brings the hidden growth into the open.</p>',
    "30": '<p><strong>Kai elegen, POshomoiOsOmen tEn basileian tou theou E en tini autEn parabolE thOmen</strong> — and he was saying: "how shall we liken the kingdom of God or with what parable shall we put it?" — the double question (<em>pOs homoiOsOmen ... en tini ... thOmen?</em>) is a rabbinic formula for introducing a parable: the question invites the hearer into the process of analogy-selection, making the comparison active rather than passive. The first-person plural (<em>homoiOsOmen ... thOmen</em> = how shall we liken, what shall we use?) includes the hearer in the act of analogizing. The self-reflective character of the question marks the mustard seed parable as consciously parabolic.</p>',
    "31": '<p><strong>Hos kokkO sinapEOs, hos hotan sparE epi tes gEs, mikroteron on pantOn tOn spermatOn tOn epi tes gEs</strong> — like a mustard seed, which when sown upon the earth, is the smallest of all the seeds upon the earth — the mustard seed\'s proverbial smallness is the starting point. <em>MikroteroN ... pantOn tOn spermatOn</em> (smallest of all the seeds) is not a botanical claim about absolute minimum seed-size but a proverbial expression for extreme smallness (the mustard seed was the standard smallest-unit in rabbinic measurement: "the tiniest of tiny things"). The point is the contrast between starting-size and ending-size, not a claim to botanical precision.</p>',
    "32": '<p><strong>Kai hotan sparE, anabainei kai ginetai meizon pantOn tOn lachanOn kai poiei kladous megalous, hOste dynasthai hypo ten skian autou ta peteina tou ouranou kataskenoun</strong> — and when sown it comes up and becomes the greatest of all the garden plants and produces large branches, so that the birds of the sky can nest in its shade — <em>meizon pantOn tOn lachanOn</em> (greatest of all the garden plants) — garden mustard (<em>sinapi</em>) can reach 2-3 meters; not a tree but large enough for the comparison. The birds nesting in the branches echoes Dan 4:12 LXX (Nebuchadnezzar\'s tree-dream) and Ezek 17:23; 31:6 — the great empires as world-trees sheltering all nations. The kingdom-as-mustard-seed that becomes a bird-sheltering plant is a deliberately modest counter-image to the imperial tree-dream: the kingdom is not violent conquest but organic growth.</p>',
    "33": '<p><strong>Kai toiautais parabolais pollais elalei autois ton logon, kathOs Edynanto akouein</strong> — and with many such parables he was speaking the word to them, as they were able to hear — <em>kathOs Edynanto akouein</em> (as they were able to hear) is the Markan editorial key to the parabolic method: the content and form of teaching is calibrated to the audience\'s current receptive capacity. This is not condescension but accommodation — meeting hearers where they are. The parables are not barriers to understanding but steps toward it, provided the hearer exercises the ears to hear (v.9,23).</p>',
    "34": '<p><strong>ChOris de parabolEs ouk elalei autois, kat\' idian de tois idiois mathEtais epelyen panta</strong> — but without a parable he was not speaking to them; but privately to his own disciples he was explaining everything — the public/private distinction: for the crowd, always parables; for the inner disciples, private explanation (<em>kat\' idian</em>). <em>Epelyen panta</em> (was explaining everything — <em>epilyO</em> = to solve, unloose, explain, the same root as <em>lyo</em> = to loose) completes the hermeneutical privilege of the insider: the disciples receive not just the parable but its key. This is not arbitrary exclusion but the logic of covenantal disclosure to those who have committed themselves to the teacher.</p>',
    "35": '<p><strong>Kai legei autois en ekeinE tE hEmera opsias genomenes, Dielthōmen eis to peran</strong> — and he said to them on that day, when evening came: "let us cross over to the other side" — <em>en ekeinE tE hEmera</em> (on that day) connects the crossing to the lakeside parabolic teaching of the day; the journey begins at the day\'s end (<em>opsias genomenes</em>). <em>Dielthōmen eis to peran</em> (let us go through to the other side) — the <em>peran</em> (the other side) is the Decapolis region, Gentile territory east of the lake. The geographical movement from Jewish Galilee toward Gentile territory mirrors the parabolic movement from concealment toward disclosure.</p>',
    "36": '<p><strong>Kai aphentes ton ochlon paralambAnousin auton hOs En en tO ploiO</strong> — and leaving the crowd, they took him along just as he was in the boat — <em>hOs En</em> (just as he was) is the vivid Markan detail: Jesus comes aboard the boat without preparation, in whatever condition the day\'s teaching left him. <strong>Kai alla ploiari En met\' autou</strong> — and other boats were with him — this detail is unique to Mark and never explained; the other boats simply appear and disappear. Their presence gives the scene the texture of an actual recollection rather than an idealized account.</p>',
    "37": '<p><strong>Kai ginetai lailaps megalE anemou, kai ta kymata epeballen eis to ploion, hOste Ede gemizesthai to ploion</strong> — and a great windstorm arose, and the waves were breaking over the boat, so that the boat was already being swamped — <em>lailaps</em> (squall, violent windstorm — used in 2 Pet 2:17 for tempests; a more vivid word than <em>seismos</em>/storm) is specifically a sudden violent gust. The Sea of Galilee is known for sudden storms caused by temperature differentials between the water and surrounding hills. <em>Ede gemizesthai</em> (already being filled, being swamped) — the danger is immediate and concrete: the boat was already taking on water.</p>',
    "38": '<p><strong>Kai autos En en tE prymne epi to proskephalaion katheudOn</strong> — and he himself was in the stern on the cushion sleeping — <em>prymna</em> (the stern, the back of the boat) is the helmsman\'s position; the <em>proskephalaion</em> (cushion, headrest — probably the leather rowing cushion or helmsman\'s seat cushion) is a vivid detail of physical exhaustion. The sleeping Jesus in the storm is both the image of utter physical depletion (the day\'s teaching has exhausted him) and the Christological paradox: the one who commands the sea (v.39) sleeps through its rage. <strong>Kai egeirousin auton kai legousin autO, Didaskale, ou melei soi hoti apollymetha?</strong> — and they woke him and said: "Teacher, don\'t you care that we are perishing?" — <em>melei soi</em> (does it concern you? do you care?) is urgent appeal, not rebuke.</p>',
    "39": '<p><strong>Kai diegertheis epetimEsen tO anemO kai eipen tE thalassE, SiOpa, pephimOso</strong> — and having been aroused he rebuked the wind and said to the sea: "Be quiet! Be muzzled!" — <em>epetimEsen</em> (rebuked — the exorcism verb, <em>epitimaO</em>, used in 1:25 for rebuking the unclean spirit) applied to the wind: Jesus addresses the storm with the same authority-command used in exorcisms. <em>SiOpa</em> (be quiet, be silent) + <em>pephimOso</em> (be muzzled — perfect passive imperative of <em>phimoO</em>, the same muzzle-verb of 1:25 used on the demon) — the identical double command: Jesus silences the storm the same way he silenced the demon. <strong>Kai ekopasen ho anemos kai egeneto galEnE megalE</strong> — and the wind ceased and there was a great calm — the <em>galEnE megalE</em> (great calm) is the Christological sign: the sea obeys as the demonic forces obey.</p>',
    "40": '<p><strong>Kai eipen autois, Ti deiloi este? OupO echete pistin?</strong> — and he said to them: "why are you cowardly? Do you not yet have faith?" — <em>deiloi</em> (cowardly, timid — from <em>deilos</em>, used in Rev 21:8 for the category of the faithless who are excluded from the new city) is a strong word: not merely "afraid" (<em>phobos</em>) but specifically cowardly under trial. <em>OupO echete pistin</em> (not yet have faith) — the <em>oupO</em> (not yet) is important: it is not a permanent verdict but a diagnosis of the disciples\' current stage. The storm-fear is not irrational (the boat was sinking) but is diagnosed as a failure of faith-confidence in the one who is with them.</p>',
    "41": '<p><strong>Kai ephobEthEsan phobon megan kai elegon pros allElous, Tis ara houtos estin hoti kai ho anemos kai hE thalassa hypakouei autO?</strong> — and they were seized with great fear and were saying to one another: "who then is this, that even the wind and the sea obey him?" — <em>ephobEthEsan phobon megan</em> (feared with great fear — cognate accusative for emphasis) — the fear after the calming is greater than the fear during the storm: awe before the divine presence exceeds terror before natural danger. <em>Tis ara houtos estin</em> (who then is this?) — the Christological question the disciples cannot yet answer. It is the question Mark poses to the reader throughout the Gospel. <em>Kai ho anemos kai hE thalassa hypakouei autO</em> — even the wind and the sea obey him — the <em>hypakouO</em> (to hear under, obey) used for the demons in 1:27 is now used for the elements of creation.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'mark')
    merge_comm(existing, MARK)
    save_comm('mkt-original', 'mark', existing)
    print('Mark 3-4 mkt-original written.')

if __name__ == '__main__':
    main()
